<template>
  <div class="product">
    <ul class="products container">
      <li v-for="(item,index) in products" :key="index" :id="item.name">
        <h3 style="text-align: left;">{{ item.title }}</h3>
        <p class="mt-20 text-pre-wrap" style="text-align: left;max-width: 70%;">{{ item.info }}</p>
        <!-- <router-link :to="'/product/'+item.id"> -->
          <!-- <img :src="`../../../static/img/services/${item.icon}`" /> -->
        <!-- </router-link> -->
				<div class="detail mt-30">
					<div class="item-box" v-for="(detail_item,detail_index) in item.detail" :key="detail_index">
            <i class="iconfont img" :class=detail_item.icon></i>
            <p class="mt-10">{{ detail_item.subTitle }}</p>
            <p class="mt-20">{{ detail_item.desc }}</p>
          </div>
				</div>

        <router-link :to="'/product/'+item.id" style="align-self: center;" class="mt-30">
          <div class="desc" >
            <p >立即使用 >> </p>
          </div>
        </router-link>
      </li>
    </ul>
  </div>
</template>
<script>
export default {
  name: "product",
  data() {
    return {
      products: [
        {
          title: "手机代理",
          info: "移动手机IP使用非常方便，只需几分钟，您就可以通过API接口或客户端获取代理IP并参照代码样例使用到业务中。",
          detail: [
            {
              icon: "iconxuanze_anquan",
              subTitle: "No restrictions",
              desc: "A large number of mobile phone IPs in each country, no restrictions on concurrent connections."
            },
            {
              icon: "iconxuanze_anquan",
              subTitle: "Easy to use",
              desc: "Real 4G / 5G mobile phone connection, one-step API call, easy to use"
            },
            {
              icon: "iconxuanze_anquan",
              subTitle: "Multi- targeting",
              desc: "Precise IP distribution ensures subdivision into accurate countries and regions. Accurate division of operators and network types makes business application more flexible."
            }
          ]
        },
        {
          title: "动态住宅",
          info:"Lucproxy提供超过2000万IP的住宅代理服务，响应时间短、数据传输速度快。\n移动手机IP使用非常方便，只需几分钟， 您就可以通过API接口或客户端获取代理IP并参照代码样例使用到业务中",
          detail: [
            {
              icon: "iconxuanze_anquan",
              subTitle: "Exclusive IP",
              desc: "Dedicated IP dedicated to your specific target site to better ensure business stability."
            },
            {
              icon: "iconxuanze_anquan",
              subTitle: "Pay by Gb",
              desc: "You can use shared IP to connect you to 50,000 to 100,000 IP pools, which consist of a fixed allocation of IP from each available country."
            },
            {
              icon: "iconxuanze_anquan",
              subTitle: "Pay by IP",
              desc: "You can choose a country / region to purchase a separate IP, unlimited bandwidth traffic cost. Pay according to the number of IPs and usage traffic."
            }
          ]
        },
        {
          title: "静态住宅",
          info:
            "Lucproxy提供全球静态住宅IP的网络超过100万， 您能够在全球多个国家拥有真实的IP，连通速度极快100%在线。\n静态住宅IP使用非常方便，只需几分钟，您就可以通过API接口或客户端获取代理IP并参照代码样例使用到业务中",
          detail: [
            {
              icon: "iconxuanze_anquan",
              subTitle: "Permanent IP",
              desc: "Use your IPs for as long as you require, whenever and wherever you need them for your purposes"
            },
            {
              icon: "iconxuanze_anquan",
              subTitle: "Never get blocked",
              desc: "Use real user residential IPs assigned by ISPs and leased to Lucproxy for your exclusive use, ensuring you never get blocked or detected."
            },
            {
              icon: "iconxuanze_anquan",
              subTitle: "Shared or exclusive",
              desc: "Use a shared or exclusive proxy or even an exclusive domain proxy which guarantees exclusivity per target websites."
            }
          ]
        },
        {
          title: "机房中心",
          info: "Lucproxy提供基于云主机构建的高品质代理服务器，为您提供高速、可信赖的网络代理服务。\n服务器代理每天可用IP数量超过10万个，可用率在95%以上，1次可提取IP数量超过50个，可以为您的业务提供强大的助力。\n服务器代理使用非常方便，只需几分钟，您就可以通过API接口或客户端获取代理IP并参照代码样例使用到业务中",
          detail: [
            {
              icon: "",
              subTitle: "Exclusive IP",
              desc: "Dedicated IP dedicated to your specific target site to better ensure business stability."
            },
            {
              icon: "",
              subTitle: "Pay by Gb",
              desc: "You can use shared IP to connect you to 50,000 to 100,000 IP pools, which consist of a fixed allocation of IP from each available country."
            },
            {
              icon: "",
              subTitle: "Pay by IP",
              desc: "You can choose a country / region to purchase a separate IP, unlimited bandwidth traffic cost. Pay according to the number of IPs and usage traffic."
            }
          ]
        }
      ],
      copy_products: []
    };
  },
  created() {
    this.$emit("headFix", ["relative", false, "rgba(3,3,3,.8)"]);
	},
	beforeRouteUpdate (to, from, next) {
		this.goAnchor(to.hash)
		next();
  },
  mounted() {
		this.goAnchor(this.$route.hash)
    this.copy_products = JSON.parse(JSON.stringify(this.products));
  },
  methods: {
    selected(item) {
      if (item.kind == 0) {
        this.products = this.copy_products;
      } else {
        this.products = this.copy_products.filter(it => it.kind === item.kind);
      }
		},
		goAnchor(hash) {
			if (hash.length == 0) {
				return
			}
			//获取元素
			let anchor = this.$el.querySelector(hash);
    	if(anchor) {
        setTimeout( () => {
					//页面没有渲染完成时是无法滚动的，因此设置延迟
					//js的内置方法，可滚动视图位置至元素位置
          anchor.scrollIntoView(); 
				},300);
			}
    } 
  }
};
</script>
<style lang="scss" scoped>

.product {
  padding-top: 5%;
  .products {
    display: flex;
    flex-direction: column;
    align-items: center;
    li {
      display: flex;
      flex-direction: column;
          // align-items: center;
      max-width: 80%;
      &:not(:first-child) {
        margin-top: 40px;
      }
      a {
        display: flex;
        flex-direction: column;
        color: #13497f;
        font-size: 1.125rem;
      }
			.detail{
        display: flex;
        .item-box{
          display: flex;
          flex-direction: column;
          align-items: center;
          max-width: 210px;
          padding: 0 20px 40px;
          
          border-radius: 6px;
          box-shadow: 1px 4px 6px rgba(0,0,0,.101961);
          &:not(:first-child) {
              margin-left: 40px;
            }
        }	
				.img{
          font-size: 30px;
        }
			}
    }
    // .desc {
		// 	color: #13497f;
		// 	font-size: 0.875rem;
		// 	font-style: normal;
		// 	font-weight: 400;
		// 	line-height: 1.5rem;
		// 	font-size: 0.875rem !important;
		// 	font-weight: 300;
		// 	text-align: left;
		// }
  }
}
// 动画
@keyframes self-zoomIn {
  from {
    border: 0px solid transparent;
    transform: scale3d(0.3, 0.3, 0.3);
  }

  50% {
    border: 3px solid #ffffff;
  }

  80% {
    border: 3px solid #ffffff;
  }

  100% {
    border: 3px solid rgba(255, 255, 255, 0.4);
  }
}
</style>



